const input = $json;

const normalize = (value) =>
  String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();

const getByHint = (hints, fallback = '') => {
  const entries = Object.entries(input);
  for (const hint of hints) {
    const h = normalize(hint);
    const found = entries.find(([k, v]) => normalize(k).includes(h) && v !== undefined && v !== null && String(v).trim() !== '');
    if (found) return String(found[1]).trim();
  }
  return fallback;
};

const problem = getByHint(['problema ou oportunidade', 'problema'], 'Nao informado');
const expectedChange = getByHint(['mudanca como voce espera ver no produto', 'mudanca esperada', 'espera ver no produto'], 'Nao informado');
const evidence = getByHint(['evidencias comprovam que a entrega esta pronta', 'evidencias', 'entrega pronta'], 'Nao informado');
const constraints = getByHint(['restricoes', 'compliance', 'integracoes proibidas', 'limites de prazo'], 'Nenhuma restricao informada');
const deployChoice = getByHint(['deploy api apos aprovacao'], 'nao').toLowerCase();

const owner = 'oliversoft-tech';
const repo = 'fastroute-changemanagement';

const githubToken = 'COLE_SEU_GITHUB_TOKEN_AQUI';
const llmModel = 'gpt-4o-mini';

const skillFastRoute = [
  'SKILL_FASTROUTE',
  '1) Produto com 3 repositorios: fastroute-domain, fastroute-api, fastroute-mobile-hybrid.',
  '2) fastroute-domain contem regras de negocio compartilhadas (validacoes, invariantes, FSM).',
  '3) fastroute-api (Node.js) faz persistencia, autorizacao, reconciliacao e conflito.',
  '4) fastroute-mobile-hybrid e offline-first e consome API + domain.',
  '5) Infra atual: VPS + Docker Compose + Nginx + Cloudflare Full Strict + GHCR.',
  '6) API via Nginx e health /health, porta interna 3002.',
  '7) N8N + Supabase existem no contexto operacional; clustering depende de lat/long validos.',
  '8) Mudanca de regra compartilhada tende a impactar domain + api + mobile.',
  '9) Evitar complexidade desnecessaria; manter arquitetura simples quando possivel.',
  '10) Sempre propor testes por repositorio e gates de regressao.'
].join('\n');

const systemPrompt = [
  'Voce e arquiteto de change management do FastRoute.',
  'Use obrigatoriamente a SKILL_FASTROUTE abaixo para analisar impacto e viabilidade.',
  '',
  skillFastRoute,
  '',
  'Retorne SOMENTE JSON valido (sem markdown) com este formato:',
  '{',
  '  resumo: string,',
  '  impactos: {',
  '    fastroute-domain: { impacto: boolean, mudancas: string[], testes: string[] },',
  '    fastroute-api: { impacto: boolean, mudancas: string[], testes: string[] },',
  '    fastroute-mobile-hybrid: { impacto: boolean, mudancas: string[], testes: string[] },',
  '    infra: { impacto: boolean, itens: string[] },',
  '    integracoes_externas: { impacto: boolean, itens: string[] }',
  '  },',
  '  viabilidade: { nivel: Alta|Media|Baixa, justificativa: string },',
  '  criterios_aceite_mapeados: [{ criterio: string, repos: string[], teste_sugerido: string }],',
  '  riscos: string[],',
  '  duvidas: string[]',
  '}'
].join('\n');

const userPrompt = [
  'Problema/Oportunidade:',
  problem,
  '',
  'Mudanca esperada no produto:',
  expectedChange,
  '',
  'Evidencias de pronto:',
  evidence,
  '',
  'Restricoes:',
  constraints
].join('\n');

return [{
  owner,
  repo,
  github_token: githubToken,
  llm_model: llmModel,
  system_prompt: systemPrompt,
  user_prompt: userPrompt,
  deploy_api: deployChoice === 'sim',
  domain_ref: 'main',
  api_ref: 'main',
  mobile_ref: 'main',
  mobile_profile: 'preview'
}];

const base = $item(0).$node['Normalize'].json;
const raw =
  $json?.text ||
  $json?.response?.text ||
  $json?.choices?.[0]?.message?.content ||
  '';

const fallbackAnalysis = {
  resumo: 'LLM nao retornou conteudo estruturado.',
  viabilidade: { nivel: 'Media', justificativa: 'Resposta vazia do modelo.' },
  impactos: {},
  criterios_aceite_mapeados: [],
  riscos: ['Sem resposta valida do LLM'],
  duvidas: ['Reexecutar analise']
};

if (!raw || typeof raw !== 'string') {
  return [{
    ...base,
    analysis: fallbackAnalysis,
    analysis_raw: {},
    llm_raw_text: ''
  }];
}

let parsed;
let cleaned = raw;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  const fence = '```';
  cleaned = raw
    .replace(`${fence}json`, '')
    .replaceAll(fence, '')
    .trim();

  try {
    parsed = JSON.parse(cleaned);
  } catch (_error) {
    parsed = {
      resumo: cleaned.slice(0, 6000) || 'Resposta nao-JSON do LLM.',
      viabilidade: { nivel: 'Media', justificativa: 'Modelo nao retornou JSON valido.' },
      impactos: {},
      criterios_aceite_mapeados: [],
      riscos: ['Falha ao parsear JSON do LLM'],
      duvidas: ['Ajustar prompt para resposta JSON estrita']
    };
  }
}

const first = (...values) => values.find((v) => v !== undefined && v !== null);
const asArray = (value) => {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === '') return [];
  return [value];
};
const asObject = (value) => (value && typeof value === 'object' && !Array.isArray(value) ? value : {});

const normalized = {
  resumo: first(parsed?.resumo, parsed?.summary, parsed?.executive_summary, parsed?.overview, ''),
  viabilidade: asObject(first(parsed?.viabilidade, parsed?.viability, parsed?.feasibility, {})),
  impactos: asObject(first(parsed?.impactos, parsed?.impacts, parsed?.impact, {})),
  criterios_aceite_mapeados: asArray(
    first(
      parsed?.criterios_aceite_mapeados,
      parsed?.acceptance_criteria_mapped,
      parsed?.mapped_acceptance_criteria,
      parsed?.acceptanceCriteriaMapped,
      []
    )
  ),
  riscos: asArray(first(parsed?.riscos, parsed?.risks, parsed?.main_risks, [])),
  duvidas: asArray(first(parsed?.duvidas, parsed?.questions, parsed?.open_questions, parsed?.openQuestions, []))
};

if (!normalized.resumo && Object.keys(asObject(parsed)).length > 0) {
  normalized.resumo = 'Analise recebida do LLM (estrutura fora do padrao esperado).';
}

return [{
  ...base,
  analysis: normalized,
  analysis_raw: asObject(parsed),
  llm_raw_text: cleaned
}];

const a = $json.analysis || {};

const analysisPayload = {
  resumo: a.resumo || '',
  viabilidade: a.viabilidade || {},
  impactos: a.impactos || {},
  criterios_aceite_mapeados: a.criterios_aceite_mapeados || [],
  riscos: a.riscos || [],
  duvidas: a.duvidas || []
};

const analysisB64 = Buffer.from(JSON.stringify(analysisPayload), 'utf8').toString('base64');

const params = {
  owner: $json.owner,
  repo: $json.repo,
  token: $json.github_token,
  deploy_api: String($json.deploy_api),
  domain_ref: $json.domain_ref,
  api_ref: $json.api_ref,
  mobile_ref: $json.mobile_ref,
  mobile_profile: $json.mobile_profile,
  analysis_b64: analysisB64
};

const q = Object.entries(params)
  .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v ?? ''))}`)
  .join('&');

const implementUrl = `http://localhost:5678/webhook/fastroute-impact-decision?${q}`;

return [{
  analysis: a,
  analysis_raw: $json.analysis_raw || {},
  llm_raw_text: $json.llm_raw_text || '',
  implement_url: implementUrl,
  aprovar_url: implementUrl,
  analysis_b64: analysisB64,
  mensagem: 'Analise LLM concluida. Clique em Implementar changes para disparar o Governance.'
}];

const q = $json.query || {};

let impactAnalysis = {};
if (q.analysis_b64) {
  try {
    const decoded = Buffer.from(String(q.analysis_b64), 'base64').toString('utf8');
    impactAnalysis = JSON.parse(decoded);
  } catch (_error) {
    impactAnalysis = {
      parse_error: true,
      observacao: 'Falha ao decodificar analysis_b64 no Decision Webhook.'
    };
  }
}

return [{
  approved: true,
  owner: q.owner || 'oliversoft-tech',
  repo: q.repo || 'fastroute-changemanagement',
  github_token: q.token || '',
  deploy_api: String(q.deploy_api || 'false').toLowerCase() === 'true',
  domain_ref: q.domain_ref || 'main',
  api_ref: q.api_ref || 'main',
  mobile_ref: q.mobile_ref || 'main',
  mobile_profile: q.mobile_profile || 'preview',
  impact_analysis: impactAnalysis
}];

const a = $json.analysis || {};
const rawObj = $json.analysis_raw || {};
const rawTxt = String($json.llm_raw_text || '');
const implementUrl = $json.implement_url || $json.aprovar_url || '';

const esc = (v) => String(v ?? '')
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;');

const toArray = (v) => {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null || v === '') return [];
  return [v];
};

const summary = esc(a.resumo || 'Sem resumo');
const viability = a.viabilidade || {};
const viabilityLevel = esc(viability.nivel || viability.level || 'Nao informado');
const viabilityReason = esc(viability.justificativa || viability.reason || 'Nao informado');

const impactSections = Object.entries(a.impactos || {}).map(([area, info]) => {
  const d = info && typeof info === 'object' ? info : {};
  const impactFlag = d.impacto === true || d.impact === true ? 'Sim' : 'Nao';
  const changes = toArray(d.mudancas || d.changes || d.itens || d.items);
  const tests = toArray(d.testes || d.tests);

  const changesHtml = changes.length
    ? `<ul>${changes.map((x) => `<li>${esc(x)}</li>`).join('')}</ul>`
    : '<p>Sem mudancas detalhadas.</p>';

  const testsHtml = tests.length
    ? `<ul>${tests.map((x) => `<li>${esc(x)}</li>`).join('')}</ul>`
    : '<p>Sem testes sugeridos.</p>';

  return [
    `<h4>${esc(area)}</h4>`,
    `<p><strong>Impacto:</strong> ${impactFlag}</p>`,
    '<p><strong>Mudancas:</strong></p>',
    changesHtml,
    '<p><strong>Testes:</strong></p>',
    testsHtml
  ].join('');
}).join('');

const criteria = toArray(a.criterios_aceite_mapeados || a.acceptance_criteria_mapped);
const criteriaHtml = criteria.length
  ? `<ol>${criteria.map((c) => {
      if (c && typeof c === 'object') {
        const criterio = esc(c.criterio || c.criterion || 'Criterio sem descricao');
        const repos = toArray(c.repos || c.repositories).map(esc).join(', ') || 'Nao informado';
        const teste = esc(c.teste_sugerido || c.suggested_test || 'Nao informado');
        return `<li><p><strong>${criterio}</strong></p><p>Repos: ${repos}</p><p>Teste: ${teste}</p></li>`;
      }
      return `<li>${esc(c)}</li>`;
    }).join('')}</ol>`
  : '<p>Sem criterios mapeados.</p>';

const risks = toArray(a.riscos || a.risks);
const risksHtml = risks.length
  ? `<ul>${risks.map((x) => `<li>${esc(x)}</li>`).join('')}</ul>`
  : '<p>Sem riscos listados.</p>';

const questions = toArray(a.duvidas || a.questions || a.open_questions);
const questionsHtml = questions.length
  ? `<ul>${questions.map((x) => `<li>${esc(x)}</li>`).join('')}</ul>`
  : '<p>Sem duvidas abertas.</p>';

const rawJson = esc(JSON.stringify(rawObj || {}, null, 2));
const rawText = esc(rawTxt.slice(0, 8000));

const formHtml = [
  '<h2>Analise de Impacto (LLM)</h2>',
  `<p><strong>Resumo:</strong> ${summary}</p>`,
  '<h3>Viabilidade</h3>',
  `<p><strong>Nivel:</strong> ${viabilityLevel}</p>`,
  `<p><strong>Justificativa:</strong> ${viabilityReason}</p>`,
  '<h3>Impactos por area</h3>',
  impactSections || '<p>Sem impactos detalhados.</p>',
  '<h3>Criterios de aceite mapeados</h3>',
  criteriaHtml,
  '<h3>Riscos</h3>',
  risksHtml,
  '<h3>Duvidas</h3>',
  questionsHtml,
  '<details><summary>Debug: JSON bruto do LLM</summary>',
  `<pre>${rawJson}</pre>`,
  '</details>',
  '<details><summary>Debug: texto bruto do LLM</summary>',
  `<pre>${rawText}</pre>`,
  '</details>',
  '<hr/>',
  '<h3>Acao</h3>',
  implementUrl
    ? `<p><a href="${implementUrl}" target="_blank" rel="noopener noreferrer">Implementar changes (disparar Governance)</a></p>`
    : '<p>URL de implementacao nao disponivel.</p>'
].join('');

return [{
  ...$json,
  form_html: formHtml
}];
